import { useParams, Link } from 'react-router-dom';
import { useState, useRef, useEffect } from 'react';
import { ArrowLeft, FileText, HelpCircle, BookOpen, Presentation, Zap, Upload, Download, Trash2 } from 'lucide-react';
import { storage, database } from '../../firebase';
import { ref as storageRef, uploadBytes, getDownloadURL, deleteObject } from 'firebase/storage';
import { ref as dbRef, push, onValue, remove } from 'firebase/database';
import { useAuth } from '../../contexts/AuthContext';

const subjectNames = {
  ds: 'Data Structures',
  os: 'Operating Systems',
  cn: 'Computer Networks',
  dbms: 'Database Management Systems',
  se: 'Software Engineering'
};

const SubjectPage = () => {
  const { deptId, subjectId } = useParams();
  const { user } = useAuth();
  const [activeTab, setActiveTab] = useState('notes');
  const [files, setFiles] = useState({});
  const [uploading, setUploading] = useState(false);
  const fileInputRef = useRef(null);
  const subjectName = subjectNames[subjectId] || 'Subject';

  // Load files from database
  useEffect(() => {
    const filesRef = dbRef(database, `materials/${deptId}/${subjectId}`);
    const unsubscribe = onValue(filesRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        setFiles(data);
      } else {
        setFiles({});
      }
    });
    return () => unsubscribe();
  }, [deptId, subjectId]);

  const handleUpload = (type) => {
    fileInputRef.current.setAttribute('data-type', type);
    fileInputRef.current.click();
  };

  const handleFileSelect = async (event) => {
    const file = event.target.files[0];
    const type = event.target.getAttribute('data-type');
    
    if (!file) return;

    setUploading(true);
    try {
      // Upload file to Firebase Storage
      const fileName = `${Date.now()}_${file.name}`;
      const fileRef = storageRef(storage, `materials/${deptId}/${subjectId}/${type}/${fileName}`);
      
      await uploadBytes(fileRef, file);
      const downloadURL = await getDownloadURL(fileRef);
      
      // Save file metadata to Realtime Database
      const fileData = {
        name: file.name,
        type: type,
        size: file.size,
        uploadedBy: user?.displayName || 'Anonymous',
        uploadedAt: Date.now(),
        downloadURL: downloadURL,
        storagePath: `materials/${deptId}/${subjectId}/${type}/${fileName}`
      };
      
      const filesRef = dbRef(database, `materials/${deptId}/${subjectId}/${type}`);
      await push(filesRef, fileData);
      
      alert(`${file.name} uploaded successfully!`);
    } catch (error) {
      console.error('Upload error:', error);
      alert('Upload failed. Please try again.');
    } finally {
      setUploading(false);
      event.target.value = '';
    }
  };

  const handleDownload = (downloadURL, fileName) => {
    const link = document.createElement('a');
    link.href = downloadURL;
    link.download = fileName;
    link.click();
  };

  const handleDelete = async (type, fileId, storagePath) => {
    if (!window.confirm('Are you sure you want to delete this file?')) return;
    
    try {
      // Delete from Storage
      const fileRef = storageRef(storage, storagePath);
      await deleteObject(fileRef);
      
      // Delete from Database
      const dbFileRef = dbRef(database, `materials/${deptId}/${subjectId}/${type}/${fileId}`);
      await remove(dbFileRef);
      
      alert('File deleted successfully!');
    } catch (error) {
      console.error('Delete error:', error);
      alert('Delete failed. Please try again.');
    }
  };

  const tabs = [
    { id: 'notes', label: 'Notes', icon: FileText },
    { id: 'pyqs', label: 'PYQs', icon: HelpCircle },
    { id: 'pdfs', label: 'PDFs', icon: BookOpen },
    { id: 'ppts', label: 'PPTs', icon: Presentation },
    { id: 'revision', label: 'Quick Revision', icon: Zap }
  ];

  const renderContent = () => {
    switch (activeTab) {
      case 'notes':
        return (
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <h3 className="text-lg font-semibold">Unit-wise Notes</h3>
              <button 
                onClick={() => handleUpload('notes')}
                className="bg-blue-600 text-white px-4 py-2 rounded-lg text-sm hover:bg-blue-700 flex items-center space-x-2"
              >
                <Upload className="w-4 h-4" />
                <span>Upload Notes</span>
              </button>
            </div>
            {[1, 2, 3, 4, 5].map(unit => (
              <div key={unit} className="bg-gray-50 p-4 rounded-lg">
                <h4 className="font-medium">Unit {unit}</h4>
                <p className="text-sm text-gray-600 mt-1">Handwritten & typed notes available</p>
              </div>
            ))}
          </div>
        );
      case 'pyqs':
        return (
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <h3 className="text-lg font-semibold">Previous Year Questions</h3>
              <button 
                onClick={() => handleUpload('pyqs')}
                className="bg-blue-600 text-white px-4 py-2 rounded-lg text-sm hover:bg-blue-700 flex items-center space-x-2"
              >
                <Upload className="w-4 h-4" />
                <span>Upload PYQ</span>
              </button>
            </div>
            <div className="bg-gray-50 p-4 rounded-lg">
              <p className="text-gray-600">Anna University, VTU, and other university papers</p>
            </div>
          </div>
        );
      case 'pdfs':
        return (
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <h3 className="text-lg font-semibold">Reference Materials</h3>
              <button 
                onClick={() => handleUpload('pdfs')}
                className="bg-blue-600 text-white px-4 py-2 rounded-lg text-sm hover:bg-blue-700 flex items-center space-x-2"
              >
                <Upload className="w-4 h-4" />
                <span>Upload PDF</span>
              </button>
            </div>
            <div className="bg-gray-50 p-4 rounded-lg">
              <p className="text-gray-600">Reference books, guides, and study materials</p>
            </div>
          </div>
        );
      case 'ppts':
        return (
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <h3 className="text-lg font-semibold">Presentations</h3>
              <button 
                onClick={() => handleUpload('ppts')}
                className="bg-blue-600 text-white px-4 py-2 rounded-lg text-sm hover:bg-blue-700 flex items-center space-x-2"
              >
                <Upload className="w-4 h-4" />
                <span>Upload PPT</span>
              </button>
            </div>
            <div className="bg-gray-50 p-4 rounded-lg">
              <p className="text-gray-600">Faculty-style concise slides</p>
            </div>
          </div>
        );
      case 'revision':
        return (
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <h3 className="text-lg font-semibold">Quick Revision</h3>
              <button 
                onClick={() => handleUpload('revision')}
                className="bg-blue-600 text-white px-4 py-2 rounded-lg text-sm hover:bg-blue-700 flex items-center space-x-2"
              >
                <Upload className="w-4 h-4" />
                <span>Add Content</span>
              </button>
            </div>
            <div className="bg-gray-50 p-4 rounded-lg">
              <p className="text-gray-600">Important questions, formulas, and key concepts</p>
            </div>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="bg-white shadow-sm border-b">
        <div className="max-w-6xl mx-auto px-4 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center space-x-4">
              <Link to={`/department/${deptId}`} className="p-2 hover:bg-gray-100 rounded-lg">
                <ArrowLeft className="w-5 h-5" />
              </Link>
              <h1 className="text-2xl font-bold text-gray-900">{subjectName}</h1>
            </div>
            <Link
              to={`/subject/${deptId}/${subjectId}/chat`}
              className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors"
            >
              Doubt Chat
            </Link>
          </div>
        </div>
      </div>

      <div className="max-w-6xl mx-auto px-4 py-6">
        <div className="bg-white rounded-lg shadow-sm">
          <div className="border-b border-gray-200">
            <nav className="flex space-x-8 px-6">
              {tabs.map((tab) => {
                const Icon = tab.icon;
                return (
                  <button
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id)}
                    className={`flex items-center space-x-2 py-4 px-1 border-b-2 font-medium text-sm ${
                      activeTab === tab.id
                        ? 'border-blue-500 text-blue-600'
                        : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                    }`}
                  >
                    <Icon className="w-4 h-4" />
                    <span>{tab.label}</span>
                  </button>
                );
              })}
            </nav>
          </div>

          <div className="p-6">
            {renderContent()}
          </div>
        </div>
      </div>
      
      {/* Hidden file input */}
      <input
        type="file"
        ref={fileInputRef}
        onChange={handleFileSelect}
        accept=".pdf,.ppt,.pptx,.doc,.docx,.jpg,.png"
        className="hidden"
      />
    </div>
  );
};

export default SubjectPage;
